<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movw %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, E820_COUNT_OFF     // count = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>
